      if(!rows.length) return '';
      return `<section class="report-section" data-report-section="${escapeHTML(cat)}"><h3>${escapeHTML(cat)}</h3><div class="report-rows">${rows.map(r=>`<div class="report-row" data-report-row data-search="${escapeHTML((r.name+' '+r.desc+' '+cat).toLowerCase())}"><button class="report-name" data-action="open-report" data-id="${r.id}">${escapeHTML(r.name)}<span class="report-desc">${escapeHTML(r.desc)}</span></button><button class="star-btn ${fav.has(r.id)?'active':''}" data-action="toggle-report-fav" data-id="${r.id}" title="Favorite">${fav.has(r.id)?'★':'☆'}</button><button class="more-btn" data-action="open-report" data-id="${r.id}">⋮</button></div>`).join('')}</div></section>`;
