      const explanation = `<div class="card tax-explain-card"><h3>Tax position explanation</h3><p>${escapeHTML(v811TaxEquationText(tax))}</p><div class="report-line"><span>Collected on sales</span><strong>${money(tax.collected)}</strong></div><div class="report-line"><span>Less recoverable ITCs</span><strong>${money(tax.itc)}</strong></div><div class="report-line"><span>Adjustments</span><strong>${money(tax.adjustments)}</strong></div><div class="report-line total"><span>Net payable before payments</span><strong>${money(tax.beforePayments)}</strong></div><div class="report-line"><span>Recorded CRA payments / credits</span><strong>${money(tax.payments)}</strong></div><div class="report-line total"><span>${escapeHTML(display.label)}</span><strong>${escapeHTML(display.amount)}</strong></div></div>`;
      body = explanation + `<div class="card table-card"><div class="toolbar"><div><h3 style="margin:0">Tax returns</h3><div class="muted small">Track filing periods, calculated amount due, payments, balances, and any credit carried forward.</div></div><div class="right"><button class="btn" data-modal="taxReturn">Prepare return</button><button class="btn primary" data-modal="taxPayment">Record payment</button></div></div>${table(['Return','Agency','Period','File date','Amount due','Payments','Balance','Credit carried forward','Status','Action'], (state.taxReturns||[]).map(r=>{ const c=v811ReturnDisplay(r); return [`<strong>${r.id}</strong>`,escapeHTML(getTaxAgency(r.agencyId).name),`${r.startDate} → ${r.endDate}`,escapeHTML(r.fileDate||'Not filed'),`<span class="amount">${money(c.amountDue)}</span>`,`<span class="amount">${money(c.payments)}</span>`,`<span class="amount">${money(c.displayBalance)}</span>`,`<span class="amount">${money(c.creditCarried)}</span>`,tagForStatus(r.status),`<button class="btn square" data-modal="taxPayment">${escapeHTML(c.action)}</button>`]; }))}</div>`;
