    (state.payments||[]).forEach(p=>{ const cname=v47CustomerName(p.customerId); const actions=[{label:'View',action:'view',primary:true}]; if(p.invoiceId) actions.push({label:'Open invoice',action:'invoice'}); if(!p.depositId) actions.push({label:'Deposit',action:'deposit'}); v47Add(rows,'Transactions',`${p.id} · ${cname}`,`Payment · ${p.date||''} · ${v47Money(p.amount)}${p.invoiceId?' · '+p.invoiceId:''}`,'Payment','$',`${p.id} ${cname} ${p.invoiceId||''} ${p.amount} ${p.date||''} received paid deposit ${p.memo||''}`,{kind:'payment',id:p.id},32,actions); });
