    (state.vendors||[]).forEach(v=>v47Add(rows,'Vendors',v.name,`${v.category||'Vendor'} · ${v.email||''} · ${v.phone||''}`,'Vendor','🏪',`${v.id} ${v.name||''} ${v.email||''} ${v.phone||''} ${v.category||''} bill supplier payable`,{kind:'vendor',id:v.id},28,[{label:'View',action:'view',primary:true},{label:'Create bill',action:'bill'}]));
    (state.products||[]).forEach(p=>v47Add(rows,'Products & Services',p.name,`${p.type||'Item'} · ${v47Money(p.price)} · ${v47AccountLabel(p.incomeAccountId||'')}`,'Item','▣',`${p.id} ${p.name||''} ${p.sku||''} ${p.type||''} ${p.price} product service sku inventory item revenue ${v47AccountLabel(p.incomeAccountId||'')}`,{kind:'product',id:p.id},24,[{label:'View',action:'view',primary:true}]));
